class APMTransaction:
    """Represents a single transaction (e.g., an HTTP request)."""

    def __init__(self, name, transaction_type="request"):
        self.id = id(self)
        self.name = name
        self.transaction_type = transaction_type
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.result = None
        self.spans = []
        self.context = {}
        self.errors = []
        self.stack_traces = []

    def end(self, result="success"):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        self.result = result

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "type": self.transaction_type,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "end_time": datetime.fromtimestamp(self.end_time).isoformat() if self.end_time else None,
            "duration_ms": round(self.duration_ms, 2) if self.duration_ms else None,
            "result": self.result,
            "spans": [s.to_dict() for s in self.spans],
            "errors": self.errors,
            "context": self.context,
        }


class APMSpan:
    """Represents a span within a transaction (e.g., a DB query, external call)."""

    def __init__(self, name, span_type="custom", subtype=None, action=None):
        self.id = id(self)
        self.name = name
        self.span_type = span_type
        self.subtype = subtype
        self.action = action
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.context = {}
        self.stack_trace = None

    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "type": self.span_type,
            "subtype": self.subtype,
            "action": self.action,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "duration_ms": round(self.duration_ms, 2) if self.duration_ms else None,
            "context": self.context,
            "stack_trace": self.stack_trace,
        }


class CustomAPMClient:
    """Custom APM client that collects and stores performance data."""

    def __init__(self, config=None):
        self.config = config or {}
        self.service_name = self.config.get("SERVICE_NAME", "my-python-app")
        self.environment = self.config.get("ENVIRONMENT", "development")
        self.transactions = []
        self.current_transaction = None
        self._capture_body = self.config.get("CAPTURE_BODY", "all")
        self._capture_headers = self.config.get("CAPTURE_HEADERS", True)
        self._collect_sql = self.config.get("CAPTURE_SQL", True)
        self._stack_trace_limit = self.config.get("STACK_TRACE_LIMIT", 50)
        self._transaction_max_spans = self.config.get("TRANSACTION_MAX_SPANS", 500)
        logger.info(
            f"Custom APM Client initialized for service '{self.service_name}' "
            f"in '{self.environment}' environment"
        )

    def begin_transaction(self, transaction_type="request", name=None):
        self.current_transaction = APMTransaction(
            name=name or "unnamed", transaction_type=transaction_type
        )
        return self.current_transaction

    def end_transaction(self, name=None, result="success"):
        if self.current_transaction:
            if name:
                self.current_transaction.name = name
            self.current_transaction.end(result=result)
            self.transactions.append(self.current_transaction)
            self._report_transaction(self.current_transaction)
            tx = self.current_transaction
            self.current_transaction = None
            return tx
        return None

    def begin_span(self, name, span_type="custom", subtype=None, action=None):
        span = APMSpan(name=name, span_type=span_type, subtype=subtype, action=action)
        if self.current_transaction:
            if len(self.current_transaction.spans) < self._transaction_max_spans:
                self.current_transaction.spans.append(span)
        return span

    def end_span(self, span):
        if span:
            span.end()
            # Capture stack trace
            import traceback
            span.stack_trace = traceback.format_stack(limit=self._stack_trace_limit)

    def capture_exception(self, exc_info=None):
        import traceback
        import sys

        if exc_info is None:
            exc_info = sys.exc_info()

        error_data = {
            "timestamp": datetime.now().isoformat(),
            "exception": {
                "type": exc_info[0].__name__ if exc_info[0] else "Unknown",
                "message": str(exc_info[1]) if exc_info[1] else "Unknown error",
                "stacktrace": traceback.format_exception(*exc_info),
            },
        }

        if self.current_transaction:
            self.current_transaction.errors.append(error_data)

        logger.error(f"APM captured exception: {error_data['exception']['type']}: "
                     f"{error_data['exception']['message']}")
        return error_data

    def set_transaction_context(self, context):
        if self.current_transaction:
            self.current_transaction.context.update(context)

    def _report_transaction(self, transaction):
        """Report transaction data (log it, send to server, etc.)."""
        tx_data = transaction.to_dict()
        logger.info(
            f"[APM] Transaction: {tx_data['name']} | "
            f"Type: {tx_data['type']} | "
            f"Duration: {tx_data['duration_ms']}ms | "
            f"Result: {tx_data['result']} | "
            f"Spans: {len(tx_data['spans'])} | "
            f"Errors: {len(tx_data['errors'])}"
        )

        # Log detailed span information
        for span in tx_data['spans']:
            logger.debug(
                f"  [APM Span] {span['name']} | "
                f"Type: {span['type']}/{span['subtype']}/{span['action']} | "
                f"Duration: {span['duration_ms']}ms"
            )

        # Store to file for analysis
        self._persist_transaction(tx_data)

    def _persist_transaction(self, tx_data):
        """Persist transaction data to a JSON file."""
        try:
            filepath = self.config.get("APM_LOG_FILE", "apm_transactions.json")
            existing = []
            if os.path.exists(filepath):
                try:
                    with open(filepath, "r") as f:
                        existing = json.load(f)
                except (json.JSONDecodeError, IOError):
                    existing = []

            existing.append(tx_data)

            # Keep only last 1000 transactions
            if len(existing) > 1000:
                existing = existing[-1000:]

            with open(filepath, "w") as f:
                json.dump(existing, f, indent=2, default=str)
        except Exception as e:
            logger.error(f"Failed to persist APM data: {e}")

    def get_metrics_summary(self):
        """Get a summary of collected metrics."""
        if not self.transactions:
            return {"message": "No transactions recorded"}

        durations = [t.duration_ms for t in self.transactions if t.duration_ms]
        error_count = sum(len(t.errors) for t in self.transactions)

        return {
            "service_name": self.service_name,
            "environment": self.environment,
            "total_transactions": len(self.transactions),
            "total_errors": error_count,
            "avg_duration_ms": round(sum(durations) / len(durations), 2) if durations else 0,
            "min_duration_ms": round(min(durations), 2) if durations else 0,
            "max_duration_ms": round(max(durations), 2) if durations else 0,
            "p95_duration_ms": round(
                sorted(durations)[int(len(durations) * 0.95)] if durations else 0, 2
            ),
        }


