class InstrumentedDatabase:
    """SQLite database wrapper with APM instrumentation."""

    def __init__(self, db_path, apm_client):
        self.db_path = db_path
        self.apm = apm_client
        self._init_db()

    def _init_db(self):
        """Initialize the database schema."""
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT NOT NULL UNIQUE,
                email TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """)
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS orders (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                product TEXT NOT NULL,
                amount REAL NOT NULL,
                status TEXT DEFAULT 'pending',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(id)
            )
        """)
        conn.commit()
        conn.close()
        logger.info(f"Database initialized at {self.db_path}")

    def execute_query(self, query, params=None, fetch=True):
        """Execute a SQL query with APM tracking."""
        # Determine query type for span naming
        query_type = query.strip().split()[0].upper()
        span_name = f"SQL {query_type}"

        span = self.apm.begin_span(
            name=span_name,
            span_type="db",
            subtype="sqlite",
            action=query_type.lower()
        )

        # Add SQL query context
        if span:
            span.context = {
                "db": {
                    "type": "sqlite",
                    "statement": query,
                    "params": str(params) if params else None,
                    "instance": self.db_path,
                }
            }

        try:
            conn = sqlite3.connect(self.db_path)
            conn.row_factory = sqlite3.Row
            cursor = conn.cursor()

            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)

            if fetch:
                results = [dict(row) for row in cursor.fetchall()]
            else:
                conn.commit()
                results = {"rowcount": cursor.rowcount, "lastrowid": cursor.lastrowid}

            conn.close()

            self.apm.end_span(span)
            return results

        except Exception as e:
            self.apm.end_span(span)
            self.apm.capture_exception()
            raise

    def create_user(self, username, email):
        return self.execute_query(
            "INSERT INTO users (username, email) VALUES (?, ?)",
            (username, email),
            fetch=False,
        )

    def get_user(self, user_id):
        results = self.execute_query(
            "SELECT * FROM users WHERE id = ?", (user_id,)
        )
        return results[0] if results else None

    def get_all_users(self):
        return self.execute_query("SELECT * FROM users")

    def create_order(self, user_id, product, amount):
        return self.execute_query(
            "INSERT INTO orders (user_id, product, amount) VALUES (?, ?, ?)",
            (user_id, product, amount),
            fetch=False,
        )

    def get_user_orders(self, user_id):
        return self.execute_query(
            "SELECT * FROM orders WHERE user_id = ?", (user_id,)
        )

    def get_order_summary(self):
        """Complex query to test SQL tracking."""
        return self.execute_query("""
            SELECT 
                u.username,
                COUNT(o.id) as order_count,
                COALESCE(SUM(o.amount), 0) as total_amount,
                COALESCE(AVG(o.amount), 0) as avg_amount
            FROM users u
            LEFT JOIN orders o ON u.id = o.user_id
            GROUP BY u.id, u.username
            ORDER BY total_amount DESC
        """)


