def apm_trace(name=None, span_type="custom", subtype=None, action=None):
    """Decorator to trace function execution with APM."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            span_name = name or f"{func.__module__}.{func.__qualname__}"
            apm_client = get_apm_client()

            span = apm_client.begin_span(
                name=span_name,
                span_type=span_type,
                subtype=subtype,
                action=action
            )

            try:
                result = func(*args, **kwargs)
                apm_client.end_span(span)
                return result
            except Exception:
                apm_client.end_span(span)
                apm_client.capture_exception()
                raise

        return wrapper
    return decorator


